noncompliant:
void function() {
    volatile int localCounter = 0; // Noncompliant: unnecessary volatile for local var
    localCounter++;
}

class DataProcessor {
private:
    volatile int memberCount; // Noncompliant: volatile member data usually inappropriate
    volatile std::string name; // Noncompliant
};

void process() {
    volatile bool flag = true; // Noncompliant: simple local variable
    if (flag) doSomething();
}

compliant:
void function() {
    int localCounter = 0; // Compliant: no volatile needed
    localCounter++;
}

class DataProcessor {
private:
    std::atomic<int> memberCount; // Compliant: use atomic for thread safety
    std::string name; // Compliant: regular member
};

void process() {
    bool flag = true; // Compliant
    if (flag) doSomething();
}

// Valid volatile usage:
volatile int* memoryMappedRegister = (volatile int*)0x12345678;
